                <p id="navName" >DIEGO YAÑEZ-LAGUNA</p>

            </div>
        </div>

        <div className="navRight navHalf">

            {/* <NavLink to="/projects" state={{ categoryPassedIn: "all" }} 
                className={activePage=="projects" ? "activeNavLink navlink pagelink":"navlink pagelink"}>
                <p>PROJECTS</p>
            </NavLink> 
